import { MongoClient, Db } from 'mongodb';
import dotenv from 'dotenv';

dotenv.config();

let client: MongoClient | null = null;
let db: Db | null = null;
let connectionError: string | null = null;
let isConnected = false;

// Fallback in-memory database for local/graceful development if MongoDB is not configured or fails
const localUsersStore: any[] = [];
const localCouponsStore: any[] = [
  { id: 'cp_1', code: 'APEX10', discountType: 'percentage', discountValue: 10, isActive: true, createdAt: new Date().toISOString() },
  { id: 'cp_2', code: 'WELCOME20', discountType: 'percentage', discountValue: 20, isActive: true, createdAt: new Date().toISOString() },
  { id: 'cp_3', code: 'STUDENT50', discountType: 'fixed', discountValue: 50, isActive: true, createdAt: new Date().toISOString() }
];
let localCoursesStore: any[] = [];

// Default Admin User Creds
const ADMIN_USER: UserDoc = {
  id: 'admin_001',
  name: 'Apex Administrator',
  email: 'admin@apexeducation.com',
  phone: '+1 (555) 019-2000',
  password: 'admin123',
  enrolledCourses: [],
  createdAt: new Date().toISOString(),
  isAdmin: true
};

// Seed default admin in local memory store
localUsersStore.push({ ...ADMIN_USER });

export interface DBStatus {
  status: 'connected' | 'fallback';
  provider: 'mongodb' | 'memory';
  uri: string;
  error: string | null;
}

export function getDBStatus(): DBStatus {
  let uri = process.env.MONGODB_URI || "mongodb+srv://itsnexverra_db_user:<db_password>@cluster0.kyzrgp8.mongodb.net/?appName=Cluster0";
  // Redact password
  if (uri.includes('@')) {
    const parts = uri.split('@');
    const credentials = parts[0].split('//')[1];
    if (credentials && credentials.includes(':')) {
      const user = credentials.split(':')[0];
      uri = `mongodb+srv://${user}:****@${parts[1]}`;
    }
  }

  return {
    status: isConnected ? 'connected' : 'fallback',
    provider: isConnected ? 'mongodb' : 'memory',
    uri,
    error: connectionError,
  };
}

export async function getDb(): Promise<Db | null> {
  if (db) return db;

  let uri = process.env.MONGODB_URI;
  if (!uri) {
    uri = "mongodb+srv://itsnexverra_db_user:<db_password>@cluster0.kyzrgp8.mongodb.net/?appName=Cluster0";
  }

  // Replace password placeholder if needed
  if (uri.includes('<db_password>')) {
    const dbPassword = process.env.DB_PASSWORD || process.env.MONGODB_PASSWORD;
    if (dbPassword) {
      uri = uri.replace('<db_password>', dbPassword);
    } else {
      connectionError = "MongoDB URI contains '<db_password>' placeholder. Please set your DB_PASSWORD in secrets or configure a full MONGODB_URI.";
      isConnected = false;
      return null;
    }
  }

  try {
    console.log("Connecting to MongoDB...");
    client = new MongoClient(uri, {
      connectTimeoutMS: 5000,
      serverSelectionTimeoutMS: 5000,
    });
    await client.connect();
    db = client.db(); // uses default db in connection string or default
    isConnected = true;
    connectionError = null;
    console.log("Successfully connected to MongoDB");
    
    // Seed admin user in MongoDB if not exists
    try {
      const usersCol = db.collection('users');
      const adminInDb = await usersCol.findOne({ email: ADMIN_USER.email });
      if (!adminInDb) {
        await usersCol.insertOne({ ...ADMIN_USER });
        console.log("Admin user seeded in MongoDB.");
      }
    } catch (err) {
      console.error("Failed to check/seed admin in MongoDB:", err);
    }

    return db;
  } catch (err: any) {
    isConnected = false;
    connectionError = err.message || "Failed to connect to MongoDB";
    console.warn("MongoDB connection failed, falling back to local memory storage:", connectionError);
    return null;
  }
}

// User-defined database interface to bridge MongoDB and Memory fallback
export interface UserDoc {
  id: string;
  name: string;
  email: string;
  phone?: string;
  password?: string;
  enrolledCourses: string[];
  createdAt: string;
  isAdmin?: boolean;
}

export interface CouponDoc {
  id: string;
  code: string;
  discountType: 'percentage' | 'fixed';
  discountValue: number;
  isActive: boolean;
  createdAt: string;
}

export interface CourseDoc {
  id: string;
  title: string;
  category: string;
  tag: string;
  price: number;
  rating: number;
  reviewCount: number;
  lessons: number;
  hours: number;
  image: string;
  description?: string;
  videoUrl?: string;
  lessonsList?: { id: string; title: string; videoUrl: string; duration?: string }[];
}

export async function dbFindUserByEmail(email: string): Promise<UserDoc | null> {
  const normalizedEmail = email.trim().toLowerCase();
  
  // Quick return for admin credentials if DB is not ready or to guarantee login
  if (normalizedEmail === ADMIN_USER.email.toLowerCase()) {
    const database = await getDb();
    if (database) {
      try {
        const col = database.collection<UserDoc>('users');
        const adminInDb = await col.findOne({ email: normalizedEmail });
        if (adminInDb) return adminInDb;
      } catch (err) {
        console.error("Error fetching admin from DB, returning in-memory:", err);
      }
    }
    return { ...ADMIN_USER };
  }

  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<UserDoc>('users');
      return await col.findOne({ email: normalizedEmail });
    } catch (err: any) {
      console.error("MongoDB find user error:", err);
    }
  }

  // Fallback storage
  return localUsersStore.find(u => u.email.toLowerCase() === normalizedEmail) || null;
}

export async function dbCreateUser(user: UserDoc): Promise<UserDoc> {
  const database = await getDb();
  
  if (database) {
    try {
      const col = database.collection<UserDoc>('users');
      await col.insertOne({ ...user });
      return user;
    } catch (err: any) {
      console.error("MongoDB create user error:", err);
    }
  }

  // Fallback storage
  localUsersStore.push(user);
  return user;
}

export async function dbGetAllUsers(): Promise<UserDoc[]> {
  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<UserDoc>('users');
      return await col.find({}).toArray();
    } catch (err: any) {
      console.error("MongoDB get all users error:", err);
    }
  }
  return localUsersStore;
}

export async function dbSaveUser(user: UserDoc): Promise<UserDoc> {
  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<UserDoc>('users');
      await col.updateOne({ id: user.id }, { $set: user }, { upsert: true });
      return user;
    } catch (err: any) {
      console.error("MongoDB save user error:", err);
    }
  }

  const index = localUsersStore.findIndex(u => u.id === user.id);
  if (index !== -1) {
    localUsersStore[index] = user;
  } else {
    localUsersStore.push(user);
  }
  return user;
}

export async function dbDeleteUser(userId: string): Promise<boolean> {
  if (userId === ADMIN_USER.id) {
    throw new Error("Cannot delete primary administrator account.");
  }
  
  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<UserDoc>('users');
      const res = await col.deleteOne({ id: userId });
      return res.deletedCount > 0;
    } catch (err: any) {
      console.error("MongoDB delete user error:", err);
    }
  }

  const index = localUsersStore.findIndex(u => u.id === userId);
  if (index !== -1) {
    localUsersStore.splice(index, 1);
    return true;
  }
  return false;
}

export async function dbUpdateUserCourses(userId: string, enrolledCourses: string[], phone?: string, name?: string): Promise<UserDoc | null> {
  const database = await getDb();

  if (database) {
    try {
      const col = database.collection<UserDoc>('users');
      const updateDoc: any = { $set: { enrolledCourses } };
      if (phone) updateDoc.$set.phone = phone;
      if (name) updateDoc.$set.name = name;

      const result = await col.findOneAndUpdate(
        { id: userId },
        updateDoc,
        { returnDocument: 'after' }
      );
      if (result) {
        const doc = (result && typeof result === 'object' && 'value' in result) ? (result as any).value : result;
        return doc as unknown as UserDoc;
      }
    } catch (err: any) {
      console.error("MongoDB update user error:", err);
    }
  }

  // Fallback storage
  const user = localUsersStore.find(u => u.id === userId);
  if (user) {
    user.enrolledCourses = enrolledCourses;
    if (phone) user.phone = phone;
    if (name) user.name = name;
    return user;
  }
  return null;
}

// ==========================================
// COURSES DB METHODS
