export async function dbGetCourses(defaultCourses: CourseDoc[]): Promise<CourseDoc[]> {
  // Initialize local memory store if empty
  if (localCoursesStore.length === 0) {
    localCoursesStore = [...defaultCourses];
  }

  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<CourseDoc>('courses');
      const courses = await col.find({}).toArray();
      if (courses.length === 0 && defaultCourses.length > 0) {
        // Seed default courses in MongoDB
        await col.insertMany(defaultCourses);
        return defaultCourses;
      }
      return courses;
    } catch (err: any) {
      console.error("MongoDB get courses error:", err);
    }
  }

  return localCoursesStore;
}

export async function dbAddCourse(course: CourseDoc): Promise<CourseDoc> {
  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<CourseDoc>('courses');
      await col.insertOne(course);
      return course;
    } catch (err: any) {
      console.error("MongoDB add course error:", err);
    }
  }

  localCoursesStore.push(course);
  return course;
}

export async function dbDeleteCourse(courseId: string): Promise<boolean> {
  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<CourseDoc>('courses');
      const res = await col.deleteOne({ id: courseId });
      return res.deletedCount > 0;
    } catch (err: any) {
      console.error("MongoDB delete course error:", err);
    }
  }

  const index = localCoursesStore.findIndex(c => c.id === courseId);
  if (index !== -1) {
    localCoursesStore.splice(index, 1);
    return true;
  }
  return false;
}

export async function dbUpdateCourse(courseId: string, updatedFields: Partial<CourseDoc>): Promise<CourseDoc | null> {
  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<CourseDoc>('courses');
      const result = await col.findOneAndUpdate(
        { id: courseId },
        { $set: updatedFields },
        { returnDocument: 'after' }
      );
      if (result) {
        const doc = (result && typeof result === 'object' && 'value' in result) ? (result as any).value : result;
        return doc as unknown as CourseDoc;
      }
    } catch (err: any) {
      console.error("MongoDB update course error:", err);
    }
  }

  const index = localCoursesStore.findIndex(c => c.id === courseId);
  if (index !== -1) {
    localCoursesStore[index] = { ...localCoursesStore[index], ...updatedFields };
    return localCoursesStore[index];
  }
  return null;
}

