export async function dbGetCoupons(): Promise<CouponDoc[]> {
  const database = await getDb();
  if (database) {
    try {
      const col = database.collection<CouponDoc>('coupons');
      const coupons = await col.find({}).toArray();
      if (coupons.length === 0) {
        await col.insertMany(localCouponsStore);
        return localCouponsStore;
      }
      return coupons;
    } catch (err: any) {
      console.error("MongoDB get coupons error:", err);
    }
  }
  return localCouponsStore;
}

